<span class="line"><span style="--shiki-light:#A626A4;--shiki-dark:#C678DD;">var</span><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;"> param = </span><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">x264_param_t</span><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">()</span></span>
